+    public var body: some View {
+        Group {
+            if let viewModel = viewModel {
+                PostDetailContent(viewModel: viewModel, showCompose: $showCompose)
+            } else {
+                ProgressView()
+            }
+        }
+        .navigationTitle("Post")
+        #if os(iOS)
+        .navigationBarTitleDisplayMode(.inline)
+        #endif
